mapper.update:
update ac_overtime_application_line
set enabled_flag = 0
where oa_order = #{oaOrder}

update ac_overtime_application
set enabled_flag = 0
where oa_order = #{oaOrder}

update ac_overtime_application
set approval_node     = #{approvalNode},
    approval_employee = #{approvalEmployee}
where oa_order = #{oaOrder}

update ac_overtime_application
set approval_result = #{approvalResult}
where oa_order = #{oa_order}

update ac_overtime_personnel_review
set dept_id    = #{deptId},
    section_id = #{sectionId},
    work_card=#{workCard}
where id = #{id}

mapper.select:
select *
from ac_overtime_application
where oa_order = #{oaOrder}

SELECT a.formatted_month, a.nick_name, a.user_name, ( SELECT dept_name FROM fnd_dept fdt WHERE fds.ext_dept_id = fdt.id ) AS dept_name, ( SELECT dept_name FROM fnd_dept fdt WHERE fds.ext_department_id = fdt.id ) AS section_name, ( SELECT dept_name FROM fnd_dept fdt WHERE fds.ext_team_id = fdt.id ) AS group_name, pej.job_name, SUM(CASE WHEN a.xxrbs = 0 THEN a.reviewhours ELSE 0 END) workDayOvertime, ROUND(SUM(CASE WHEN a.xxrbs = 1 THEN a.reviewhours ELSE 0 END), 1) AS restDayOvertime, CAST(ROUND(SUM(CASE WHEN a.leave_type = '调休' THEN a.number ELSE 0 END), 2) AS DECIMAL(18,2)) AS TXTS, CAST(ROUND(SUM(CASE WHEN a.leave_type = '调休' THEN a.number ELSE 0 END) * 7.5, 2) AS DECIMAL(18,2)) AS TXXS, SUM(CASE WHEN a.leave_type = '年假' THEN a.number ELSE 0 END) NJ, ROUND(SUM(CASE WHEN a.leave_type = '事假' THEN a.number ELSE 0 END),2) SJ, SUM(CASE WHEN a.leave_type = '病假' THEN a.number ELSE 0 END) BJ, SUM(CASE WHEN a.leave_type = '婚假' THEN a.number ELSE 0 END) HJ, SUM(CASE WHEN a.leave_type = '产假' THEN a.number ELSE 0 END) CJ, SUM(CASE WHEN a.leave_type = '陪产假' THEN a.number ELSE 0 END) PCJ, SUM(CASE WHEN a.leave_type = '丧假' THEN a.number ELSE 0 END) SAJ, SUM(CASE WHEN a.leave_type = '工伤假' THEN a.number ELSE 0 END) GSJ, SUM(CASE WHEN a.leave_type = '计划生育假' THEN a.number ELSE 0 END) JHSYJ, SUM(CASE WHEN a.leave_type = '公假' THEN a.number ELSE 0 END) GJ, SUM(CASE WHEN a.leave_type = '育儿假' THEN a.number ELSE 0 END) YEJ, SUM(CASE WHEN a.leave_type = '护理假' THEN a.number ELSE 0 END) HLJ FROM (SELECT CONVERT (VARCHAR (7), alal.start_time, 120) AS formatted_month, ala.nick_name, ala.user_name, (CASE WHEN alal.leave_type = '事假' OR alal.leave_type = '年假' OR alal.leave_type = '调休' OR alal.leave_type = '病假' THEN alal.work_number ELSE alal.number END) AS number, -- COALESCE( -- ala.hr_total, -- 如果 ala.hr_total 不为 NULL，则使用它的值 -- CASE -- WHEN alal.leave_type = '事假' OR alal.leave_type = '年假' OR alal.leave_type = '调休' OR alal.leave_type = '病假' THEN -- alal.work_number -- ELSE -- alal.number -- END -- ) AS number, -- CASE WHEN alal.leave_type = '事假' or alaL.leave_type = '年假' THEN alal.work_number ELSE alal.number END as number, -- alal.number, -- ala.total_number, alal.leave_type, 0 AS reviewhours, 99 AS xxrbs FROM ac_leave_application ala JOIN ac_leave_application_line alal ON ala.oa_order = alal.oa_order and ala.version = alal.version WHERE YEAR (start_time) = CAST (SUBSTRING (#{checkMonth} , 1 , 4) AS INT) AND MONTH (start_time) = CAST (SUBSTRING (#{checkMonth} , 6 , 2) AS INT) AND ala.approval_result = 'Pass' and ala.enabled_flag = 1 UNION ALL SELECT CONVERT ( VARCHAR ( 7 ), aoal.start_time, 120 ) AS formatted_month, aoal.nick_name, aoal.user_name, 0 AS txts, '加班' AS LeaveType, ROUND(aoal.review_hours, 1) AS review_hours, -- aoal.review_hours, c.XXRBS FROM ac_overtime_application aoa JOIN ac_overtime_application_line aoal ON aoa.oa_order = aoal.oa_order LEFT JOIN ( SELECT c.RQ, C.XXRBS FROM v_kq_date c ) c ON CONVERT ( VARCHAR ( 10 ), aoal.review_startTime, 23 ) = c.RQ WHERE YEAR (aoal.review_startTime) = CAST (SUBSTRING (#{checkMonth} , 1 , 4) AS INT) AND MONTH (aoal.review_startTime) = CAST (SUBSTRING (#{checkMonth} , 6 , 2) AS INT) AND aoa.approval_result = 'Pass' and aoal.enabled_flag = 1) a JOIN pm_employee pe ON a.user_name = pe.work_card LEFT JOIN pm_employee_job pej ON pej.employee_id = pe.id INNER JOIN fnd_dept fds ON fds.id = pej.dept_id where fds.ext_dept_id IN
#{deptId}
and pej.job_main_flag = 1 AND pej.enabled_flag = 1 AND a.nick_name != '' GROUP BY a.formatted_month, a.nick_name, a.user_name, pej.attribute2, pej.dept_name, pej.attribute4, pej.job_name,fds.ext_dept_id,fds.ext_department_id,fds.ext_team_id order by a.formatted_month desc OFFSET (#{pages}) * #{sizes} ROWS FETCH NEXT #{sizes} ROWS ONLY

select pe.administration_category
from pm_employee pe
where pe.enabled_flag = 1 and pe.leave_flag = 0 and pe.work_card = #{workCard}

