update ac_overtime_application
  set   approval_result   = #{approvalResult,jdbcType=VARCHAR}
where id = #{id,jdbcType=BIGINT}


update ac_overtime_application
  set    approval_node      = #{approvalNode,jdbcType=VARCHAR},
         approval_employee  = #{approvalEmployee,jdbcType=VARCHAR}
where id = #{id,jdbcType=BIGINT}
